const test = require("node:test");
const assert = require("node:assert");
const { greet } = require("../src/greeting.js");
const { bound } = require("../src/bound.js");
const { run } = require("../src/cli.js");

test("greet uses core strings", () => {
  assert.deepStrictEqual(greet("ada lovelace"), { slug: "ada-lovelace", title: "Ada Lovelace" });
  assert.deepStrictEqual(greet("Grace HOPPER"), { slug: "grace-hopper", title: "Grace Hopper" });
});

test("bound uses core clamp", () => {
  assert.strictEqual(bound(-5), 0);
  assert.strictEqual(bound(250), 100);
  assert.strictEqual(bound(42), 42);
});

test("run composes greet and bound into one line", () => {
  assert.strictEqual(run(["--name", "ada lovelace", "--score", "42"]), "Ada Lovelace scored 42");
  assert.strictEqual(run(["--name", "grace hopper", "--score", "250"]), "Grace Hopper scored 100");
});
